import os
from flask import Flask, request, jsonify
import pymysql

app = Flask(__name__)

# Load environment variables from Cloud Functions
PROJECT_ID = os.environ['GOOGLE_CLOUD_PROJECT']
INSTANCE_CONNECTION_NAME = f'{PROJECT_ID}:{os.environ["SQL_INSTANCE"]}'
DB_USER = os.environ["SQL_USER"]
DB_PASSWORD = os.environ["SQL_PASSWORD"]

# Establish a connection to the database
def get_db():
    return pymysql.connect(
        host='127.0.0.1',
        user=DB_USER,
        password=DB_PASSWORD,
        db=os.environ['SQL_DB'],
        charset='utf8mb4',
        cursorclass=pymysql.cursors.DictCursor
    )

# Validate and sanitize HTTP request parameters
def validate_params(params):
    allowed_fields = ['name', 'email']
    for field in params:
        if field not in allowed_fields:
            return False, f'Invalid parameter: {field}'
        if not isinstance(params[field], str) or len(params[field]) == 0:
            return False, f'Missing or empty value for parameter: {field}'
    return True, None

# Build dynamic SQL query from HTTP request parameters
def build_query(params):
    query = 'SELECT * FROM table_name WHERE '
    conditions = []
    for field in params:
        if params[field]:
            conditions.append(f'{field} LIKE "%{params[field]}%"')
    query += ' AND '.join(conditions)
    return query

# Handle HTTP requests
@app.route('/search', methods=['GET'])
def search():
    try:
        # Get request parameters
        params = request.args.to_dict()
        
        # Validate and sanitize parameters
        valid, error = validate_params(params)
        if not valid:
            return jsonify({'error': error}), 400
        
        # Establish a database connection
        db = get_db()
        
        # Build dynamic SQL query
        query = build_query(params)
        
        # Execute the query
        with db.cursor() as cursor:
            cursor.execute(query)
            results = cursor.fetchall()
        
        # Close the database connection
        db.close()
        
        return jsonify(results), 200
    
    except Exception as e:
        print(f'Error: {e}')
        return jsonify({'error': 'Internal Server Error'}), 500

if __name__ == '__main__':
    app.run(debug=True)